package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;
  private JsonObject jsonObject;

  @BeforeEach
  public void setUp() throws Exception {
    jsonObject = new JsonObject();
    jsonObject.addProperty("key", "value");
    jsonTreeReader = new JsonTreeReader(jsonObject);

    // We need to push an object and an iterator to stack to simulate state before endObject()
    // Use reflection to access private methods push and fields stackSize, stack

    Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
    pushMethod.setAccessible(true);

    // Push the JsonObject (the object to be ended)
    pushMethod.invoke(jsonTreeReader, jsonObject);

    // Push an iterator (simulate the iterator of the object's entry set)
    Object iterator = jsonObject.entrySet().iterator();
    pushMethod.invoke(jsonTreeReader, iterator);

    // Set stackSize accordingly (should be 2 now)
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 2);

    // Initialize pathNames and pathIndices arrays at index 1 (stackSize - 1)
    Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
    pathNamesField.setAccessible(true);
    String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);
    pathNames[1] = "key";

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    pathIndices[1] = 5;
  }

  @Test
  public void testEndObject_Normal() throws Exception {
    // Call endObject, which should:
    // - expect JsonToken.END_OBJECT
    // - nullify pathNames[stackSize - 1]
    // - popStack twice (iterator and object)
    // - increment pathIndices[stackSize - 1] if stackSize > 0

    // We need to mock expect(JsonToken) to not throw exception
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Spy to override expect to do nothing (since we cannot mock final class easily)
    JsonTreeReader spyReader = spy(jsonTreeReader);
    doNothing().when(spyReader).expect(JsonToken.END_OBJECT);

    spyReader.endObject();

    // Access stackSize via reflection
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int stackSize = stackSizeField.getInt(spyReader);

    // Access pathNames via reflection
    Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
    pathNamesField.setAccessible(true);
    String[] pathNames = (String[]) pathNamesField.get(spyReader);

    assertNull(pathNames[stackSize]);

    // Validate stackSize decreased by 2 (from 2 to 0)
    int stackSizeAfter = stackSizeField.getInt(spyReader);
    assertEquals(0, stackSizeAfter);

    // Validate pathIndices[stackSize - 1] incremented if stackSize > 0
    // Since stackSize is 0 now, no increment should happen, so test initial case:
    // Reset and test with stackSize > 0

    // Re-setup state for stackSize > 0 condition
    // Push one object to stack again
    Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
    pushMethod.setAccessible(true);
    pushMethod.invoke(spyReader, jsonObject);

    // Set stackSize = 1
    stackSizeField.setInt(spyReader, 1);

    // Access pathIndices via reflection
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(spyReader);
    pathIndices[0] = 5;

    // Set pathNames[0] to some non-null value
    pathNames[0] = "name";

    // Call endObject again
    spyReader.endObject();

    // Now stackSize should be 0 after popping twice (popStack twice)
    int stackSizeAfterSecond = stackSizeField.getInt(spyReader);
    assertEquals(0, stackSizeAfterSecond);

    // pathIndices[stackSize - 1] increment should have happened before popping stacks?
    // Actually, increment happens only if stackSize > 0 after popping twice.
    // After popping twice from 1, stackSize is -1? No, popStack reduces stackSize by 1 each call.
    // So from 1, popStack twice would make stackSize -1, which is invalid.
    // So we must test with stackSize=3 to validate increment.

    // Reset stackSize to 3 and push accordingly
    // Clear stack and push three objects
    stackSizeField.setInt(spyReader, 0);
    // Clear pathNames and pathIndices
    for (int i = 0; i < pathNames.length; i++) {
      pathNames[i] = null;
      pathIndices[i] = 0;
    }

    pushMethod.invoke(spyReader, jsonObject);
    pushMethod.invoke(spyReader, jsonObject.entrySet().iterator());
    pushMethod.invoke(spyReader, jsonObject);
    stackSizeField.setInt(spyReader, 3);

    // Set pathIndices[2] = 5
    pathIndices[2] = 5;
    pathNames[2] = "name";

    spyReader.endObject();

    // After popping twice, stackSize should be 1
    int stackSizeAfterThird = stackSizeField.getInt(spyReader);
    assertEquals(1, stackSizeAfterThird);

    // pathIndices[stackSize - 1] = pathIndices[0] should be incremented by 1
    assertEquals(1, pathIndices[0]);

    // pathNames[stackSize - 1] is not null (should remain unchanged)
    assertNull(pathNames[stackSizeAfterThird]);
  }
}
